public class IfForms {
    public static void main(String[] args) {
        int x = 42;

        // ── Simple if ──
        if (x > 0) System.out.println("Positive");  // braces optional for single stmt

        // ── if-else ──
        if (x % 2 == 0) {
            System.out.println("Even");
        } else {
            System.out.println("Odd");
        }

        // ── if-else if-else chain ──
        int score = 78;
        if (score >= 90)      System.out.println("A");
        else if (score >= 80) System.out.println("B");
        else if (score >= 70) System.out.println("C");
        else if (score >= 60) System.out.println("D");
        else                  System.out.println("F");
        // Output: C

        // ── Nested if ──
        int a = 5, b = 10;
        if (a > 0) {
            if (b > 0) {
                System.out.println("Both positive");
            }
        }

        // ── Compound conditions ──
        int age = 25;
        if (age >= 18 && age <= 65) System.out.println("Working age");
        if (age < 18 || age > 65)   System.out.println("Outside working age");
    }
}

public class TernaryDemo {
    public static void main(String[] args) {
        int x = 7;

        // ── Basic form ──
        String result = (x > 5) ? "big" : "small";
        System.out.println(result);                   // big

        // ── Directly in print ──
        System.out.println(x % 2 == 0 ? "Even" : "Odd");  // Odd

        // ── Nested ternary (use cautiously) ──
        int n = 0;
        String sign = (n > 0) ? "positive" : (n < 0) ? "negative" : "zero";
        System.out.println(sign);  // zero

        // ── With arithmetic ──
        int abs = (x >= 0) ? x : -x;  // absolute value
        System.out.println(abs);       // 7

        // ── Ternary result must match type ──
        // int val = (x > 5) ? "big" : 0;  // COMPILE ERROR: String vs int
        int val = (x > 5) ? 100 : 0;
        System.out.println(val);  // 100
    }
}

public class SwitchDemo {
    public static void main(String[] args) {
        int day = 3;

        // ── Clean switch (each case has break) ──
        switch (day) {
            case 1: System.out.println("Monday");    break;
            case 2: System.out.println("Tuesday");   break;
            case 3: System.out.println("Wednesday"); break;
            case 4: System.out.println("Thursday");  break;
            case 5: System.out.println("Friday");    break;
            default: System.out.println("Weekend");
        }
        // Output: Wednesday

        // ── Intentional fall-through ──
        switch (day) {
            case 1:
            case 2:
            case 3:
            case 4:
            case 5:
                System.out.println("Weekday");  // all 1-5 reach here
                break;
            default:
                System.out.println("Weekend");
        }
        // Output: Weekday

        // ── switch on String (Java 7+) ──
        String color = "red";
        switch (color) {
            case "red":   System.out.println("Stop");     break;
            case "green": System.out.println("Go");       break;
            case "yellow":System.out.println("Caution");  break;
            default:      System.out.println("Invalid");
        }
        // Output: Stop
    }
}

public class SwitchExpression {
    public static void main(String[] args) {
        int day = 3;

        // ── Arrow case: no fall-through, no break needed ──
        String name = switch (day) {
            case 1 -> "Monday";
            case 2 -> "Tuesday";
            case 3 -> "Wednesday";
            case 4 -> "Thursday";
            case 5 -> "Friday";
            default -> "Weekend";
        };
        System.out.println(name);  // Wednesday

        // ── Multiple values per case ──
        String type = switch (day) {
            case 1, 2, 3, 4, 5 -> "Weekday";
            case 6, 7           -> "Weekend";
            default             -> "Invalid";
        };
        System.out.println(type);  // Weekday
    }
}

public class ForLoops {
    public static void main(String[] args) {
        // ── Standard forward ──
        for (int i = 0; i < 5; i++) System.out.print(i + " ");
        System.out.println();  // 0 1 2 3 4

        // ── 1-indexed ──
        for (int i = 1; i <= 5; i++) System.out.print(i + " ");
        System.out.println();  // 1 2 3 4 5

        // ── Reverse ──
        for (int i = 5; i >= 1; i--) System.out.print(i + " ");
        System.out.println();  // 5 4 3 2 1

        // ── Step by 2 ──
        for (int i = 0; i <= 10; i += 2) System.out.print(i + " ");
        System.out.println();  // 0 2 4 6 8 10

        // ── Enhanced for-each (arrays and collections) ──
        int[] arr = {10, 20, 30, 40};
        for (int x : arr) System.out.print(x + " ");
        System.out.println();  // 10 20 30 40

        // ── Multiple variables in header ──
        for (int i = 0, j = 10; i < j; i++, j--)
            System.out.print("(" + i + "," + j + ") ");
        System.out.println();  // (0,10) (1,9) (2,8) (3,7) (4,6)
    }
}

public class WhileDemo {
    public static void main(String[] args) {
        // ── while: may not execute at all ──
        int n = 0;
        while (n > 0) {         // 0 > 0 is false immediately
            System.out.println("while body");  // NEVER printed
            n--;
        }
        System.out.println("After while: " + n);  // After while: 0

        // ── do-while: always executes at least once ──
        int m = 0;
        do {
            System.out.println("do body");  // Printed ONCE
            m--;
        } while (m > 0);          // 0 > 0 is false: stops after 1 run
        System.out.println("After do-while: " + m);  // After do-while: -1

        // ── do-while: digit extraction (classic use case) ──
        int num = 1234;
        System.out.print("Digits reversed: ");
        do {
            System.out.print(num % 10 + " ");  // last digit
            num /= 10;
        } while (num > 0);
        System.out.println();  // 4 3 2 1
        // Works correctly even for num=0 (prints 0, then stops)
    }
}

public class BreakContinue {
    public static void main(String[] args) {
        // ── break: exit on first match ──
        for (int i = 0; i < 10; i++) {
            if (i == 5) break;
            System.out.print(i + " ");  // 0 1 2 3 4
        }
        System.out.println();

        // ── continue: skip multiples of 3 ──
        for (int i = 1; i <= 10; i++) {
            if (i % 3 == 0) continue;
            System.out.print(i + " ");  // 1 2 4 5 7 8 10
        }
        System.out.println();

        // ── Labeled break: exit BOTH loops ──
        outer:
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (i == 1 && j == 1) break outer;  // exits both loops
                System.out.print("(" + i + "," + j + ") ");
            }
        }
        System.out.println();  // (0,0) (0,1) (0,2) (1,0)

        // ── Labeled continue ──
        outer2:
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (j == 1) continue outer2;  // skip to next i
                System.out.print("(" + i + "," + j + ") ");
            }
        }
        System.out.println();  // (0,0) (1,0) (2,0)
    }
}

