public class Q3 {
    public static void main(String[] args) {
        int sum = 0;
        for (int i = 1; i <= 10; i++) {
            if (i % 2 == 0) continue;
            if (i > 7) break;
            sum += i;
        }
        System.out.println(sum);
    }
}

public class Q4 {
    public static void main(String[] args) {
        int a = 5;
        while (a < 5) {
            System.out.print("W" + a + " ");
            a++;
        }
        System.out.println("after-while");

        int b = 5;
        do {
            System.out.print("D" + b + " ");
            b++;
        } while (b < 5);
        System.out.println("after-do");
    }
}

public class Q5 {
    public static void main(String[] args) {
        int count = 0;
        outer:
        for (int i = 1; i <= 4; i++) {
            for (int j = 1; j <= 4; j++) {
                if (i * j > 6) break outer;
                count++;
            }
        }
        System.out.println(count);
    }
}

